import { Component, OnInit } from '@angular/core';
import { ReconciliationService } from '../services/reconciliation.service';
import { DashboardResult } from '../../../core/models/index';

@Component({
  selector: 'app-dashboard',
  templateUrl: './dashboard.component.html',
  styleUrls: ['./dashboard.component.scss'],
})
export class DashboardComponent implements OnInit {
  dashboard: DashboardResult | null = null;
  loading = false;
  error = '';

  constructor(private readonly reconciliationService: ReconciliationService) {}

  ngOnInit(): void {
    this.loadDashboard();
  }

  private loadDashboard(): void {
    this.loading = true;
    this.error = '';

    this.reconciliationService.getDashboard().subscribe({
      next: (result) => {
        this.dashboard = result;
        this.loading = false;
      },
      error: (err: Error) => {
        this.error = err.message || 'No se pudo cargar el dashboard';
        this.loading = false;
      },
    });
  }
}
<div class="dashboard-card">
  <h2>Dashboard de conciliaciones</h2>

  <div *ngIf="loading" class="loading">Cargando métricas...</div>
  <div *ngIf="error" class="error-message">{{ error }}</div>

  <div *ngIf="dashboard" class="metrics-grid">
    <div class="metric-card">
      <span class="metric-label">Conciliaciones</span>
      <span class="metric-value">{{ dashboard.totalReconciliations }}</span>
    </div>

    <div class="metric-card">
      <span class="metric-label">Cuentas</span>
      <span class="metric-value">{{ dashboard.totalAccounts }}</span>
    </div>

    <div class="metric-card">
      <span class="metric-label">Incidentes</span>
      <span class="metric-value">{{ dashboard.totalIncidents }}</span>
    </div>

    <div class="metric-card">
      <span class="metric-label">Diferencia total</span>
      <span class="metric-value">{{ dashboard.totalDifference | number:'1.0-2' }}</span>
    </div>
  </div>
</div>
